import { useMemo, useState, useEffect, useRef } from "react";
import { useMarket } from "@/lib/MarketContext";
import { openItem } from "@/components/landing/DetailDrawer";
import Header from "@/components/landing/Header";
import Footer from "@/components/landing/Footer";
import { fmt } from "@/lib/parseItem";
import { Search } from "lucide-react";

export default function LookupPage() {
  const { market } = useMarket();
  const [q, setQ] = useState("");
  const inputRef = useRef(null);

  useEffect(() => {
    if (inputRef.current) {
      inputRef.current.focus();
    }
  }, []);

  const results = useMemo(() => {
    if (!market?.rowsByKey || !q.trim()) return [];
    const lowerQ = q.toLowerCase();
    return Array.from(market.rowsByKey.values())
      .filter(item => item.name.toLowerCase().includes(lowerQ))
      .slice(0, 20);
  }, [market, q]);

  const handleCopy = async (text) => {
    if (navigator.clipboard && window.isSecureContext) {
      await navigator.clipboard.writeText(text);
    } else {
      const ta = document.createElement("textarea");
      ta.value = text;
      ta.style.position = "fixed";
      ta.style.opacity = "0";
      document.body.appendChild(ta);
      ta.select();
      document.execCommand("copy");
      document.body.removeChild(ta);
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Header />
      <div className="flex-1 container mx-auto max-w-md px-4 py-6">
        <div className="relative mb-4">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-zinc-500" />
          <input
            ref={inputRef}
            type="text"
            value={q}
            onChange={(e) => setQ(e.target.value)}
            placeholder="Search items..."
            className="w-full pl-10 pr-4 py-3 rounded-lg bg-bg-deeper border border-white/10 text-white placeholder-zinc-500 font-mono text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500/50"
          />
        </div>
        {results.length > 0 && (
          <ul className="divide-y divide-white/10">
            {results.map((item) => (
              <li key={item.key}>
                <button
                  onClick={() => openItem(item.key)}
                  className="w-full text-left p-3 hover:bg-white/5 transition-colors flex items-center justify-between"
                >
                  <div className="flex-1 min-w-0">
                    <div className="text-sm text-white">{item.name}</div>
                    <div className="text-xs text-zinc-500">
                      {item.tier > 0 && `T${item.tier} · `}{fmt(item.median)} coins
                    </div>
                  </div>
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      handleCopy(item.key);
                    }}
                    className="text-zinc-500 hover:text-emerald-400 text-xs px-2"
                  >
                    Copy
                  </button>
                </button>
              </li>
            ))}
          </ul>
        )}
        {!q && (
          <p className="text-center text-zinc-500 text-sm mt-8 font-mono">
            Search for items by name
          </p>
        )}
      </div>
      <Footer />
    </div>
  );
}